 check(warnOut," warning ",expectWarns);
 }
 void check(String text,String expectText,int expectCount){
 int foundCount = 0;
 for(String line : text.split("[rn]+")){
 if(line.contains(expectText))foundCount ++;
 }
 if(foundCount != expectCount){
 error("" + foundCount + ",expected: " + expectCount);
 }
 }
 private List < String > list(String...args){
 return Arrays.asList(args);
 }
 void error(String msg){
 System.err.println(msg);
 errors ++;
 }
 int count;
 int errors;
 }

