package org.apache.ws.security.dom.message;
 import org.apache.ws.security.dom.WSConstants;
 import org.apache.ws.security.dom.WSEncryptionPart;
 import org.apache.ws.security.dom.WSSConfig;
 import org.apache.ws.security.common.crypto.Crypto;
 import org.apache.ws.security.common.crypto.CryptoType;
 import org.apache.ws.security.common.ext.WSSecurityException;
 import org.apache.ws.security.dom.message.token.KerberosSecurity;
 import org.apache.ws.security.dom.message.token.Reference;
 import org.apache.ws.security.dom.message.token.SecurityTokenReference;
 import org.apache.ws.security.dom.util.WSSecurityUtil;
 import org.apache.xml.security.encryption.EncryptedData;
 import org.apache.xml.security.encryption.XMLCipher;
 import org.apache.xml.security.encryption.XMLEncryptionException;
 import org.apache.xml.security.keys.KeyInfo;
 import org.apache.xml.security.utils.Base64;
 import org.w3c.dom.Attr;
 import org.w3c.dom.Document;
 import org.w3c.dom.Element;
 import org.w3c.dom.NamedNodeMap;
 import org.w3c.dom.Node;
 import javax.crypto.KeyGenerator;
 import javax.crypto.SecretKey;
 import java.security.cert.X509Certificate;
 import java.util.ArrayList;
 import java.util.List;
 public class WSSecEncrypt extends WSSecEncryptedKey {
 private static org.apache.commons.logging.Log log = org.apache.commons.logging.LogFactory.getLog(WSSecEncrypt.class);
 private byte [ ] embeddedKey = null;
 private String embeddedKeyName = null;
 private SecurityTokenReference securityTokenReference = null;
 private boolean encryptSymmKey = true;
 private String customReferenceValue;
 private boolean encKeyIdDirectId;
 private boolean embedEncryptedKey;
 public WSSecEncrypt(){
 super();
 }
 public WSSecEncrypt(WSSConfig config){
 super(config);
 }
 public void setKey(byte [ ] key){
 embeddedKey = key;
 }
 public void setKeyEnc(String keyEnc){
 keyEncAlgo = keyEnc;
 }
 public void setEmbeddedKeyName(String embeddedKeyName){
 this.embeddedKeyName = embeddedKeyName;
 }
 public void prepare(Document doc,Crypto crypto)throws WSSecurityException {
 document = doc;
 if(ephemeralKey == null){
 if(symmetricKey == null){
 KeyGenerator keyGen = getKeyGenerator();
 symmetricKey = keyGen.generateKey();
 }
 ephemeralKey = symmetricKey.getEncoded();
 }
 if(symmetricKey == null){
 symmetricKey = WSSecurityUtil.prepareSecretKey(symEncAlgo,ephemeralKey);
 }
 if(encryptSymmKey){
 X509Certificate remoteCert = useThisCert;
 if(remoteCert == null){
 CryptoType cryptoType = new CryptoType(CryptoType.TYPE.ALIAS);
 cryptoType.setAlias(user);
 X509Certificate [ ] certs = crypto.getX509Certificates(cryptoType);
 if(certs == null || certs.length <= 0){
 throw new WSSecurityException(WSSecurityException.ErrorCode.FAILURE,"",new Object [ ] {
 user,"encryption" }
);
 }
 remoteCert = certs [ 0 ];
 }
 prepareInternal(symmetricKey,remoteCert,crypto);
 }
 else {
 encryptedEphemeralKey = ephemeralKey;
 }
 }
 public Document build(Document doc,Crypto crypto,WSSecHeader secHeader)throws WSSecurityException {
 doDebug = log.isDebugEnabled();
 if(keyIdentifierType == WSConstants.EMBEDDED_KEYNAME || keyIdentifierType == WSConstants.EMBED_SECURITY_TOKEN_REF){
 encryptSymmKey = false;
 document = doc;
 if(symmetricKey == null){
 if(embeddedKey == null){
 throw new WSSecurityException(WSSecurityException.ErrorCode.FAILURE,"");
 }
 symmetricKey = WSSecurityUtil.prepareSecretKey(symEncAlgo,embeddedKey);
 }
 }
 else {
 prepare(doc,crypto);
 }
 if(envelope == null){
 envelope = document.getDocumentElement();
 }
 if(parts == null){
 parts = new ArrayList < WSEncryptionPart >(1);
 String soapNamespace = WSSecurityUtil.getSOAPNamespace(envelope);
 WSEncryptionPart encP = new WSEncryptionPart(WSConstants.ELEM_BODY,soapNamespace,"Content");
 parts.add(encP);
 }
 if(doDebug){
 log.debug("");
 }
 Element refs = encryptForRef(null,parts);
 if(encryptedKeyElement != null){
 addInternalRefElement(refs);
 prependToHeader(secHeader);
 }
 else {
 addExternalRefElement(refs,secHeader);
 }
 if(bstToken != null){
 prependBSTElementToHeader(secHeader);
 }
 log.debug("");
 return doc;
 }
 public Element encryptForRef(Element dataRef,List < WSEncryptionPart > references)throws WSSecurityException {
 KeyInfo keyInfo = createKeyInfo();
 List < String > encDataRefs = doEncryption(document,getWsConfig(),keyInfo,symmetricKey,symEncAlgo,references,callbackLookup);
 if(dataRef == null){
 dataRef = document.createElementNS(WSConstants.ENC_NS,WSConstants.ENC_PREFIX + "");
 if(! encryptSymmKey){
 WSSecurityUtil.setNamespace(dataRef,WSConstants.ENC_NS,WSConstants.ENC_PREFIX);
 }
 }
 return createDataRefList(document,dataRef,encDataRefs);
 }
 public Element encryptForInternalRef(Element dataRef,List < WSEncryptionPart > references)throws WSSecurityException {
 return encryptForRef(dataRef,references);
 }
 public Element encryptForExternalRef(Element dataRef,List < WSEncryptionPart > references)throws WSSecurityException {
 return encryptForRef(dataRef,references);
 }
 public void addInternalRefElement(Element dataRef){
 encryptedKeyElement.appendChild(dataRef);
 }
 public void addExternalRefElement(Element dataRef,WSSecHeader secHeader){
 WSSecurityUtil.prependChildElement(secHeader.getSecurityHeader(),dataRef);
 }
 public static List < String > doEncryption(Document doc,WSSConfig config,KeyInfo keyInfo,SecretKey secretKey,String encryptionAlgorithm,List < WSEncryptionPart > references,CallbackLookup callbackLookup)throws WSSecurityException {
 XMLCipher xmlCipher = null;
 try {
 xmlCipher = XMLCipher.getInstance(encryptionAlgorithm);
 }
 catch(XMLEncryptionException ex){
 throw new WSSecurityException(WSSecurityException.ErrorCode.UNSUPPORTED_ALGORITHM,ex);
 }
 List < String > encDataRef = new ArrayList < String >();
 for(int part = 0;
 part < references.size();
 part ++){
 WSEncryptionPart encPart = references.get(part);
 if(callbackLookup == null){
 callbackLookup = new DOMCallbackLookup(doc);
 }
 List < Element > elementsToEncrypt = WSSecurityUtil.findElements(encPart,callbackLookup,doc);
 if(elementsToEncrypt == null || elementsToEncrypt.size()== 0){
 throw new WSSecurityException(WSSecurityException.ErrorCode.FAILURE,"noEncElement",new Object [ ] {
 " {
 " + encPart.getNamespace()+ " }
 " + encPart.getName()}
);
 }
 String modifier = encPart.getEncModifier();
 for(Element elementToEncrypt : elementsToEncrypt){
 String id = encryptElement(doc,elementToEncrypt,modifier,config,xmlCipher,secretKey,keyInfo);
 encPart.setEncId(id);
 encDataRef.add("#" + id);
 }
 if(part !=(references.size()- 1)){
 try {
 keyInfo = new KeyInfo((Element)keyInfo.getElement().cloneNode(true),null);
 }
 catch(Exception ex){
 throw new WSSecurityException(WSSecurityException.ErrorCode.FAILED_ENCRYPTION,ex);
 }
 }
 }
 return encDataRef;
 }
 private static String encryptElement(Document doc,Element elementToEncrypt,String modifier,WSSConfig config,XMLCipher xmlCipher,SecretKey secretKey,KeyInfo keyInfo)throws WSSecurityException {
 boolean content = "Content".equals(modifier)? true : false;
 String xencEncryptedDataId = config.getIdAllocator().createId("ED-",elementToEncrypt);
 try {
 String headerId = "";
 if("Header".equals(modifier)){
 Element elem = doc.createElementNS(WSConstants.WSSE11_NS,"wsse11:" + WSConstants.ENCRYPTED_HEADER);
 WSSecurityUtil.setNamespace(elem,WSConstants.WSSE11_NS,WSConstants.WSSE11_PREFIX);
 String wsuPrefix = WSSecurityUtil.setNamespace(elem,WSConstants.WSU_NS,WSConstants.WSU_PREFIX);
 headerId = config.getIdAllocator().createId("EH-",elementToEncrypt);
 elem.setAttributeNS(WSConstants.WSU_NS,wsuPrefix + ":Id",headerId);
 Node parent = elementToEncrypt.getParentNode();
 elementToEncrypt =(Element)parent.replaceChild(elem,elementToEncrypt);
 elem.appendChild(elementToEncrypt);
 NamedNodeMap map = elementToEncrypt.getAttributes();
 for(int i = 0;
 i < map.getLength();
 i ++){
 Attr attr =(Attr)map.item(i);
 if(attr.getNamespaceURI().equals(WSConstants.URI_SOAP11_ENV)|| attr.getNamespaceURI().equals(WSConstants.URI_SOAP12_ENV)){
 String soapEnvPrefix = WSSecurityUtil.setNamespace(elem,attr.getNamespaceURI(),WSConstants.DEFAULT_SOAP_PREFIX);
 elem.setAttributeNS(attr.getNamespaceURI(),soapEnvPrefix + ":" + attr.getLocalName(),attr.getValue());
 }
 }
 }
 xmlCipher.init(XMLCipher.ENCRYPT_MODE,secretKey);
 EncryptedData encData = xmlCipher.getEncryptedData();
 encData.setId(xencEncryptedDataId);
 encData.setKeyInfo(keyInfo);
 xmlCipher.doFinal(doc,elementToEncrypt,content);
 return xencEncryptedDataId;
 }
 catch(Exception ex){
 throw new WSSecurityException(WSSecurityException.ErrorCode.FAILED_ENCRYPTION,ex);
 }
 }
 private KeyInfo createKeyInfo()throws WSSecurityException {
 KeyInfo keyInfo = new KeyInfo(document);
 if(embedEncryptedKey){
 keyInfo.addUnknownElement(getEncryptedKeyElement());
 }
 else if(keyIdentifierType == WSConstants.ENCRYPTED_KEY_SHA1_IDENTIFIER){
 SecurityTokenReference secToken = new SecurityTokenReference(document);
 secToken.addWSSENamespace();
 if(customReferenceValue != null){
 secToken.setKeyIdentifierEncKeySHA1(customReferenceValue);
 }
 else {
 byte [ ] encodedBytes = WSSecurityUtil.generateDigest(encryptedEphemeralKey);
 secToken.setKeyIdentifierEncKeySHA1(Base64.encode(encodedBytes));
 }
 secToken.addTokenType(WSConstants.WSS_ENC_KEY_VALUE_TYPE);
 keyInfo.addUnknownElement(secToken.getElement());
 }
 else if(keyIdentifierType == WSConstants.EMBEDDED_KEYNAME){
 keyInfo.addKeyName(embeddedKeyName == null ? user : embeddedKeyName);
 }
 else if(WSConstants.WSS_SAML_KI_VALUE_TYPE.equals(customReferenceValue)){
 SecurityTokenReference secToken = new SecurityTokenReference(document);
 secToken.addWSSENamespace();
 secToken.addTokenType(WSConstants.WSS_SAML_TOKEN_TYPE);
 secToken.setKeyIdentifier(WSConstants.WSS_SAML_KI_VALUE_TYPE,encKeyId);
 keyInfo.addUnknownElement(secToken.getElement());
 }
 else if(WSConstants.WSS_SAML2_KI_VALUE_TYPE.equals(customReferenceValue)){
 SecurityTokenReference secToken = new SecurityTokenReference(document);
 secToken.addWSSENamespace();
 secToken.addTokenType(WSConstants.WSS_SAML2_TOKEN_TYPE);
 secToken.setKeyIdentifier(WSConstants.WSS_SAML2_KI_VALUE_TYPE,encKeyId);
 keyInfo.addUnknownElement(secToken.getElement());
 }
 else if(WSConstants.WSS_KRB_KI_VALUE_TYPE.equals(customReferenceValue)){
 SecurityTokenReference secToken = new SecurityTokenReference(document);
 secToken.addWSSENamespace();
 secToken.addTokenType(WSConstants.WSS_GSS_KRB_V5_AP_REQ);
 secToken.setKeyIdentifier(customReferenceValue,encKeyId,true);
 keyInfo.addUnknownElement(secToken.getElement());
 }
 else if(securityTokenReference != null){
 Element tmpE = securityTokenReference.getElement();
 tmpE.setAttributeNS(WSConstants.XMLNS_NS,"xmlns:" + tmpE.getPrefix(),tmpE.getNamespaceURI());
 keyInfo.addUnknownElement(securityTokenReference.getElement());
 }
 else {
 SecurityTokenReference secToken = new SecurityTokenReference(document);
 secToken.addWSSENamespace();
 Reference ref = new Reference(document);
 if(encKeyIdDirectId){
 ref.setURI(encKeyId);
 }
 else {
 ref.setURI("#" + encKeyId);
 }
 if(customReferenceValue != null){
 ref.setValueType(customReferenceValue);
 }
 secToken.setReference(ref);
 if(KerberosSecurity.isKerberosToken(customReferenceValue)){
 secToken.addTokenType(customReferenceValue);
 }
 else if(! WSConstants.WSS_USERNAME_TOKEN_VALUE_TYPE.equals(customReferenceValue)){
 secToken.addTokenType(WSConstants.WSS_ENC_KEY_VALUE_TYPE);
 }
 keyInfo.addUnknownElement(secToken.getElement());
 }
 Element keyInfoElement = keyInfo.getElement();
 keyInfoElement.setAttributeNS(WSConstants.XMLNS_NS,"xmlns:" + WSConstants.SIG_PREFIX,WSConstants.SIG_NS);
 return keyInfo;
 }
 public static Element createDataRefList(Document doc,Element referenceList,List < String > encDataRefs){
 for(String dataReferenceUri : encDataRefs){
 Element dataReference = doc.createElementNS(WSConstants.ENC_NS,WSConstants.ENC_PREFIX + "");
 dataReference.setAttributeNS(null,"URI",dataReferenceUri);
 referenceList.appendChild(dataReference);
 }
 return referenceList;
 }
 public SecurityTokenReference getSecurityTokenReference(){
 return securityTokenReference;
 }
 public void setSecurityTokenReference(SecurityTokenReference reference){
 securityTokenReference = reference;
 }
 public boolean isEncryptSymmKey(){
 return encryptSymmKey;
 }
 public void setEncryptSymmKey(boolean encryptSymmKey){
 this.encryptSymmKey = encryptSymmKey;
 }
 public void setCustomReferenceValue(String customReferenceValue){
 this.customReferenceValue = customReferenceValue;
 }
 public void setEncKeyIdDirectId(boolean b){
 encKeyIdDirectId = b;
 }
 public void setEmbedEncryptedKey(boolean embedEncryptedKey){
 this.embedEncryptedKey = embedEncryptedKey;
 }
 public boolean isEmbedEncryptedKey(){
 return embedEncryptedKey;
 }
 }

