 dataRef = document.createElementNS(WSConstants.ENC_NS,WSConstants.ENC_PREFIX + "");
 if(! encryptSymmKey){
 WSSecurityUtil.setNamespace(dataRef,WSConstants.ENC_NS,WSConstants.ENC_PREFIX);
 }
 }
 return createDataRefList(document,dataRef,encDataRefs);
 }
 public Element encryptForInternalRef(Element dataRef,List < WSEncryptionPart > references)throws WSSecurityException {
