 if(lastCode == '/'){
 continue;
 }
 code = '-';
 }
 else if(chr == 'B' ||(chr == 'P' && nextChar != 'H')){
 code = '1';
 }
 else if((chr == 'D' || chr == 'T')&& ! arrayContains(new char [ ] {
 'S','C','Z' }
 ,nextChar)){
 code = '2';
 }
 else if(arrayContains(new char [ ] {
 'W','F','P','V' }
 ,chr)){
 code = '3';
 }
 else if(arrayContains(new char [ ] {
 'G','K','Q' }
 ,chr)){
 code = '4';
 }
 else if(chr == 'X' && ! arrayContains(new char [ ] {
 'C','K','Q' }
 ,lastChar)){
 code = '4';
 input.addLeft('S');
 rightLength ++;
 }
 else if(chr == 'S' || chr == 'Z'){
 code = '8';
 }
 else if(chr == 'C'){
