 public abstract class BaseNCodec implements BinaryEncoder,BinaryDecoder {
 public static final int MIME_CHUNK_SIZE = 76;
 public static final int PEM_CHUNK_SIZE = 64;
 private static final int DEFAULT_BUFFER_RESIZE_FACTOR = 2;
 private static final int DEFAULT_BUFFER_SIZE = 8192;
 protected static final int MASK_8BITS = 0xff;
 protected static final byte PAD_DEFAULT = '=';
 protected final byte PAD = PAD_DEFAULT;
 private final int unencodedBlockSize;
 private final int encodedBlockSize;
 protected final int lineLength;
 private final int chunkSeparatorLength;
 protected byte [ ] buffer;
 protected int pos;
 private int readPos;
 protected boolean eof;
 protected int currentLinePos;
 protected int modulus;
 protected BaseNCodec(int unencodedBlockSize,int encodedBlockSize,int lineLength,int chunkSeparatorLength){
 this.unencodedBlockSize = unencodedBlockSize;
 this.encodedBlockSize = encodedBlockSize;
 this.lineLength =(lineLength > 0 && chunkSeparatorLength > 0)?(lineLength / encodedBlockSize)* encodedBlockSize : 0;
 this.chunkSeparatorLength = chunkSeparatorLength;
 }
 boolean hasData(){
 return this.buffer != null;
 }
 int available(){
 return buffer != null ? pos - readPos : 0;
 }
 protected int getDefaultBufferSize(){
 return DEFAULT_BUFFER_SIZE;
 }
 private void resizeBuffer(){
 if(buffer == null){
 buffer = new byte [ getDefaultBufferSize()];
 pos = 0;
 readPos = 0;
 }
 else {
 byte [ ] b = new byte [ buffer.length * DEFAULT_BUFFER_RESIZE_FACTOR ];
 System.arraycopy(buffer,0,b,0,buffer.length);
 buffer = b;
 }
 }
 protected void ensureBufferSize(int size){
 if((buffer == null)||(buffer.length < pos + size)){
 resizeBuffer();
 }
 }
 int readResults(byte [ ] b,int bPos,int bAvail){
 if(buffer != null){
 int len = Math.min(available(),bAvail);
 System.arraycopy(buffer,readPos,b,bPos,len);
 readPos += len;
 if(readPos >= pos){
 buffer = null;
 }
 return len;
 }
 return eof ? - 1 : 0;
 }
 protected static boolean isWhiteSpace(byte byteToCheck){
 switch(byteToCheck){
 case ' ' : case '\n' : case '\r' : case '\t' : return true;
 default : return false;
 }
 }
 private void reset(){
 buffer = null;
 pos = 0;
 readPos = 0;
 currentLinePos = 0;
 modulus = 0;
 eof = false;
 }
