 }
 else {
 throw new DecoderException("");
 }
 }
 public byte [ ] decode(String pArray){
 return decode(StringUtils.getBytesUtf8(pArray));
 }
 public byte [ ] decode(byte [ ] pArray){
 reset();
 if(pArray == null || pArray.length == 0){
 return pArray;
 }
 decode(pArray,0,pArray.length);
 decode(pArray,0,- 1);
 byte [ ] result = new byte [ pos ];
 readResults(result,0,result.length);
 return result;
 }
 public byte [ ] encode(byte [ ] pArray){
 reset();
 if(pArray == null || pArray.length == 0){
 return pArray;
 }
 encode(pArray,0,pArray.length);
 encode(pArray,0,- 1);
 byte [ ] buf = new byte [ pos - readPos ];
 readResults(buf,0,buf.length);
 return buf;
 }
 public String encodeAsString(byte [ ] pArray){
 return StringUtils.newStringUtf8(encode(pArray));
 }
 abstract void encode(byte [ ] pArray,int i,int length);
 abstract void decode(byte [ ] pArray,int i,int length);
 protected abstract boolean isInAlphabet(byte value);
 public boolean isInAlphabet(byte [ ] arrayOctet,boolean allowWSPad){
 for(int i = 0;
 i < arrayOctet.length;
 i ++){
 if(! isInAlphabet(arrayOctet [ i ])&&(! allowWSPad ||(arrayOctet [ i ] != PAD)&& ! isWhiteSpace(arrayOctet [ i ]))){
 return false;
 }
 }
 return true;
 }
 public boolean isInAlphabet(String basen){
 return isInAlphabet(StringUtils.getBytesUtf8(basen),true);
 }
 protected boolean containsAlphabetOrPad(byte [ ] arrayOctet){
 if(arrayOctet == null){
 return false;
 }
 for(int i = 0;
 i < arrayOctet.length;
 i ++){
 if(PAD == arrayOctet [ i ] || isInAlphabet(arrayOctet [ i ])){
 return true;
 }
 }
 return false;
 }
 public long getEncodedLength(byte [ ] pArray){
 long len =((pArray.length + unencodedBlockSize - 1)/ unencodedBlockSize)*(long)encodedBlockSize;
 if(lineLength > 0){
 len +=((len + lineLength - 1)/ lineLength)* chunkSeparatorLength;
 }
 return len;
 }
 }

